import React from 'react'
import { Link } from "react-router-dom";
import ApiRequest from '../../Services/ApiRequest'
import { APP_URL } from '../../Helpers/AppConstant'
import MenteeSidebar from '../../Components/Layouts/DashboardLayout/MenteeLayout/MenteeSidebar';
import HeaderMenteeDashboard from '../../Components/Layouts/DashboardLayout/MenteeLayout/HeaderMenteeDashboard';

class BrowseCareer extends React.Component {

    state = {
        isAnimationLoaded: false,
        spaces: []
    }

    componentDidMount = async () => {
        const response = await ApiRequest.getRequest('/getSpaces');
        if (response && response.status === 200 && response.data.spaces.length !== 0) {
            this.setState({
                spaces: response.data.spaces
            })
        }
    }
    spacesCardHtml() {
        if (this.state.spaces) {
            return (
                this.state.spaces.map(el => {
                    console.log(el);
                    return (
                        <div className="col-md-6">
                            <div className="row mar-width-0 browse-section">
                                <div className="col-1 browse-section-inner-1">
                                    <img src={el.icon} className="cb1" alt="" />
                                </div>
                                <div className="col-11 browse-section-inner-2">
                                    <h3>{el.title}</h3>
                                    <p>{el.summary}</p>
                                    <div className="text-center"> <img src={el.image} className="cb5" alt="" /></div>
                                    <Link to="/FindMentor" className="get-browse-btn">My Mentors</Link>
                                </div>
                            </div>
                        </div>
                    );
                })
            );
        }
    }

    render() {
        console.log(this.spacesCardHtml)
        return (
            <>
                <div className="container-fluid dashboard-body-bg p-0">
                    <div className='dashboard'>
                        <MenteeSidebar />
                        <div className='dashboard-app'>
                            <HeaderMenteeDashboard />
                            <div className='dashboard-content'>
                                <div className="container-fluid dashboardWrap">


                                    <div className="container pb-4 pt-5">
                                        <div className="col-md-12 works-inner-1">
                                            <h2>My Space</h2>
                                        </div>
                                        <div className="row mar-width-0">
                                            {this.spacesCardHtml()}
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </>
            // <>
            //     <Header />
            //     <div className="container-fluid browse-wrapper p-0">


            //         <div className="container pb-4 pt-5">
            //             <div className="col-md-12 works-inner-1">
            //                 <h2>My Space: Project Management</h2>
            //             </div>
            //             <div className="row mar-width-0">
            //                 {this.spacesCardHtml()}
            //             </div>
            //         </div>
            //     </div>

            //     <Footer />
            // </>

        )
    }
}

export default BrowseCareer
